    88→// NewDefaultManager creates a new defaultManager.
    89→func NewDefaultManager() Manager {
    90→	s := &defaultManager{}
    91→	s.completed.Store(false)
    92→	s.managedResourceInfos = make(map[*ResourceInfo]struct{})
